package handlers

import (
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"

	"github.com/alexmorbo/seasonfill/application/runtimeconfig"
	"github.com/alexmorbo/seasonfill/interface/http/dto"
)

const runtimeConfigBodyLimit = 64 << 10

// RuntimeConfigHandler is the GET/PUT handler for
// /api/v1/config/runtime. AutoGeneratedAPIKey is read-only — any value
// the client sends on PUT is silently dropped (the usecase does not
// read it).
type RuntimeConfigHandler struct {
	uc     *runtimeconfig.UseCase
	logger *slog.Logger
}

func NewRuntimeConfigHandler(uc *runtimeconfig.UseCase, logger *slog.Logger) *RuntimeConfigHandler {
	if logger == nil {
		logger = slog.Default()
	}
	return &RuntimeConfigHandler{uc: uc, logger: logger}
}

// Get returns the current runtime_config row.
//
// @Summary     Get runtime configuration
// @Tags        config
// @Produce     json
// @Success     200  {object}  dto.RuntimeConfigDTO
// @Failure     401  {object}  dto.ErrorResponse
// @Failure     500  {object}  dto.ErrorResponse
// @Header      200  {string}  Last-Modified  "RFC1123 of updated_at"
// @Security    CookieAuth
// @Security    ApiKeyAuth
// @Router      /config/runtime [get]
func (h *RuntimeConfigHandler) Get(c *gin.Context) {
	out, ts, err := h.uc.Get(c.Request.Context())
	if err != nil {
		h.writeError(c, err)
		return
	}
	if !ts.IsZero() {
		c.Header("Last-Modified", ts.UTC().Format(http.TimeFormat))
	}
	c.JSON(http.StatusOK, outputToDTO(out))
}

// Update full-replaces the runtime_config row.
//
// @Summary     Update runtime configuration
// @Tags        config
// @Accept      json
// @Produce     json
// @Param       body  body      dto.RuntimeConfigDTO  true  "Runtime config"
// @Success     200   {object}  dto.RuntimeConfigDTO
// @Failure     400   {object}  dto.ErrorResponse
// @Failure     401   {object}  dto.ErrorResponse
// @Failure     412   {object}  dto.ErrorResponse
// @Failure     500   {object}  dto.ErrorResponse
// @Header      200   {string}  Last-Modified  "RFC1123 of updated_at"
// @Security    CookieAuth
// @Security    ApiKeyAuth
// @Router      /config/runtime [put]
func (h *RuntimeConfigHandler) Update(c *gin.Context) {
	var raw dto.RuntimeConfigDTO
	if !readRuntimeConfigBody(c, &raw) {
		return
	}
	in, err := dtoToInput(raw)
	if err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: err.Error(), Code: "BAD_REQUEST",
		})
		return
	}
	var iusPtr *time.Time
	if hdr := c.GetHeader("If-Unmodified-Since"); hdr != "" {
		t, err := http.ParseTime(hdr)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
				Error: "If-Unmodified-Since: " + err.Error(),
				Code:  "BAD_REQUEST",
			})
			return
		}
		iusPtr = &t
	}
	out, ts, err := h.uc.Update(c.Request.Context(), in, iusPtr)
	if err != nil {
		if errors.Is(err, runtimeconfig.ErrStaleWrite) {
			h.writeStaleWrite(c)
			return
		}
		h.writeError(c, err)
		return
	}
	if !ts.IsZero() {
		c.Header("Last-Modified", ts.UTC().Format(http.TimeFormat))
	}
	c.JSON(http.StatusOK, outputToDTO(out))
}

// writeStaleWrite emits the 412 STALE_WRITE response with a
// Last-Modified header sourced from the current stored row so the
// caller can re-issue the PUT immediately without an extra GET.
// runtime_config is a singleton — Get falls back to defaults with
// a zero timestamp if the row was somehow purged, in which case the
// header is omitted.
func (h *RuntimeConfigHandler) writeStaleWrite(c *gin.Context) {
	_, ts, err := h.uc.Get(c.Request.Context())
	if err == nil && !ts.IsZero() {
		c.Header("Last-Modified", ts.UTC().Format(http.TimeFormat))
	}
	c.AbortWithStatusJSON(http.StatusPreconditionFailed, dto.ErrorResponse{
		Error: "runtime_config was modified by another client",
		Code:  "STALE_WRITE",
	})
}

func (h *RuntimeConfigHandler) writeError(c *gin.Context, err error) {
	var verr *runtimeconfig.ValidationError
	switch {
	case errors.As(err, &verr):
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: verr.Error(), Code: verr.Code,
		})
	default:
		h.logger.ErrorContext(c.Request.Context(), "runtimeconfig.handler.error",
			slog.String("error", err.Error()))
		c.AbortWithStatusJSON(http.StatusInternalServerError, dto.ErrorResponse{
			Error: "internal server error",
		})
	}
}

// dtoToInput parses duration strings at the handler boundary and
// constructs a typed runtimeconfig.Input for the usecase.
func dtoToInput(d dto.RuntimeConfigDTO) (runtimeconfig.Input, error) {
	jitter, err := parseDuration("cron.jitter", d.Cron.Jitter)
	if err != nil {
		return runtimeconfig.Input{}, err
	}
	shutdown, err := parseDuration("scan.shutdown_grace", d.Scan.ShutdownGrace)
	if err != nil {
		return runtimeconfig.Input{}, err
	}
	sweep, err := parseDuration("scan.cooldown_sweep", d.Scan.CooldownSweep)
	if err != nil {
		return runtimeconfig.Input{}, err
	}
	sessionTTL, err := parseDuration("auth.session_ttl", d.Auth.SessionTTL)
	if err != nil {
		return runtimeconfig.Input{}, err
	}
	return runtimeconfig.Input{
		Cron: runtimeconfig.CronInput{
			Enabled:  d.Cron.Enabled,
			Schedule: d.Cron.Schedule,
			OnStart:  d.Cron.OnStart,
			Jitter:   jitter,
		},
		Scan: runtimeconfig.ScanInput{
			ShutdownGrace: shutdown,
			CooldownSweep: sweep,
		},
		DryRun: d.DryRun,
		GlobalRateLimit: runtimeconfig.GlobalRateLimitInput{
			RPM: d.GlobalRateLimit.RPM, Burst: d.GlobalRateLimit.Burst,
		},
		Auth: runtimeconfig.AuthInput{
			SessionTTL:     sessionTTL,
			SecureCookie:   d.Auth.SecureCookie,
			TrustedProxies: append([]string(nil), d.Auth.TrustedProxies...),
			Mode:           normalizeIncomingMode(d.Auth.Mode),
			LocalBypass:    d.Auth.LocalBypass,
			LocalNetworks:  append([]string(nil), d.Auth.LocalNetworks...),
			OIDC: runtimeconfig.OIDCInput{
				Issuer:        d.Auth.OIDC.Issuer,
				ClientID:      d.Auth.OIDC.ClientID,
				ClientSecret:  d.Auth.OIDC.ClientSecret,
				RedirectURL:   d.Auth.OIDC.RedirectURL,
				Scopes:        append([]string(nil), d.Auth.OIDC.Scopes...),
				UsernameClaim: d.Auth.OIDC.UsernameClaim,
				AllowedGroups: append([]string(nil), d.Auth.OIDC.AllowedGroups...),
				GroupsClaim:   d.Auth.OIDC.GroupsClaim,
			},
		},
	}, nil
}

// normalizeIncomingMode treats empty as the safe default. Any unknown
// value flows through to the usecase, which returns INVALID_AUTH_MODE.
func normalizeIncomingMode(m string) string {
	if m == "" {
		return "forms"
	}
	return m
}

// outputToDTO converts usecase Output to the wire DTO. Durations are
// rendered as Go-style strings (e.g. "30s").
func outputToDTO(out runtimeconfig.Output) dto.RuntimeConfigDTO {
	return dto.RuntimeConfigDTO{
		Cron: dto.RuntimeCronDTO{
			Enabled:  out.Cron.Enabled,
			Schedule: out.Cron.Schedule,
			OnStart:  out.Cron.OnStart,
			Jitter:   out.Cron.Jitter.String(),
		},
		Scan: dto.RuntimeScanDTO{
			ShutdownGrace: out.Scan.ShutdownGrace.String(),
			CooldownSweep: out.Scan.CooldownSweep.String(),
		},
		DryRun: out.DryRun,
		GlobalRateLimit: dto.RuntimeRateLimitDTO{
			RPM: out.GlobalRateLimit.RPM, Burst: out.GlobalRateLimit.Burst,
		},
		Auth: dto.RuntimeAuthDTO{
			SessionTTL:     out.Auth.SessionTTL.String(),
			SecureCookie:   out.Auth.SecureCookie,
			TrustedProxies: append([]string(nil), out.Auth.TrustedProxies...),
			Mode:           out.Auth.Mode,
			LocalBypass:    out.Auth.LocalBypass,
			LocalNetworks:  append([]string(nil), out.Auth.LocalNetworks...),
			SessionEpoch:   out.Auth.SessionEpoch,
			OIDC: dto.RuntimeOIDCDTO{
				Issuer:                  out.Auth.OIDC.Issuer,
				ClientID:                out.Auth.OIDC.ClientID,
				RedirectURL:             out.Auth.OIDC.RedirectURL,
				Scopes:                  append([]string(nil), out.Auth.OIDC.Scopes...),
				UsernameClaim:           out.Auth.OIDC.UsernameClaim,
				AllowedGroups:           append([]string(nil), out.Auth.OIDC.AllowedGroups...),
				GroupsClaim:             out.Auth.OIDC.GroupsClaim,
				ClientSecretConfigured:  out.Auth.OIDC.ClientSecretConfigured,
				ClientSecretEnvOverride: out.Auth.OIDC.ClientSecretEnvOverride,
				// ClientSecret intentionally omitted on GET.
			},
		},
		AutoGeneratedAPIKey: out.AutoGeneratedAPIKey,
		UpdatedAt:           out.UpdatedAt,
	}
}

// parseDuration parses a Go-style duration string at the handler
// boundary. Returns a plain error (not ValidationError) because the
// handler converts parse failures to 400 BAD_REQUEST directly.
func parseDuration(field, raw string) (time.Duration, error) {
	if strings.TrimSpace(raw) == "" {
		return 0, fmt.Errorf("%s: required (Go duration string e.g. \"30s\")", field)
	}
	d, err := time.ParseDuration(raw)
	if err != nil {
		return 0, fmt.Errorf("%s: %w", field, err)
	}
	return d, nil
}

func readRuntimeConfigBody(c *gin.Context, out *dto.RuntimeConfigDTO) bool {
	ct := c.GetHeader("Content-Type")
	if !strings.HasPrefix(ct, "application/json") {
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: "content-type must be application/json", Code: "BAD_REQUEST",
		})
		return false
	}
	c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, runtimeConfigBodyLimit)
	raw, err := io.ReadAll(c.Request.Body)
	if err != nil {
		var maxErr *http.MaxBytesError
		if errors.As(err, &maxErr) {
			c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
				Error: "payload too large", Code: "BAD_REQUEST",
			})
			return false
		}
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: "cannot read body", Code: "BAD_REQUEST",
		})
		return false
	}
	if err := json.Unmarshal(raw, out); err != nil {
		c.AbortWithStatusJSON(http.StatusBadRequest, dto.ErrorResponse{
			Error: "malformed body", Code: "BAD_REQUEST",
		})
		return false
	}
	return true
}
